def solve(nums: Array[Long]): Boolean = {
  val n = nums.length
  if (n < 3) return false

  var p = 1
  while (p < n - 1 && nums(p) > nums(p - 1)) {
    p += 1
  }

  if (p == 1) return false

  var q = p
  while (q < n - 1 && nums(q) > nums(q + 1)) {
    q += 1
  }

  val increasing = (0 until p).forall(i => nums(i) < nums(i + 1))
  val decreasing = (p until q).forall(i => nums(i) > nums(i + 1))
  val increasing2 = (q until n).forall(i => nums(i) < nums(i + 1))

  increasing && decreasing && increasing2
}
